laravel-serializable-closure://function (\Illuminate\Http\Request $request) {
    \Log::info('Dashboard hit', [
        'auth' => \portal_check(),
        'user_id' => \portal_id(),
        'portal' => \App\Support\PortalSession::currentPortal(),
        'admin_authenticated' => \Illuminate\Support\Facades\Auth::guard(\App\Support\PortalAuth::ADMIN_GUARD)->check(),
        'participant_authenticated' => \Illuminate\Support\Facades\Auth::guard(\App\Support\PortalAuth::PARTICIPANT_GUARD)->check(),
        'active_guard' => \App\Support\PortalAuth::activeGuard(),
        'session_id' => $request->session()->getId(),
        'session_cookie' => \config('session.cookie'),
        'has_token' => $request->has('token'),
        'token_len' => $request->has('token') ? \strlen($request->query('token')) : 0,
    ]);

    // If token is present and user is not authenticated, handle centralized login
    if ($request->has('token') && ! \portal_check()) {
        \Log::info('Dashboard handling centralized token', [
            'session_id' => $request->session()->getId(),
        ]);

        return \app(\App\Http\Controllers\CentralizedLoginController::class)->handle($request);
    }

    // If not authenticated and no token, redirect to the appropriate login page
    if (! \portal_check()) {
        \Log::warning('Dashboard unauthenticated redirect', [
            'session_id' => $request->session()->getId(),
            'portal' => \App\Support\PortalSession::currentPortal(),
            'session_cookie' => \config('session.cookie'),
            'has_token' => $request->has('token'),
        ]);

        $loginRoute = \App\Support\PortalSession::currentPortal() === \App\Support\PortalSession::PARTICIPANT
            ? 'participant.login'
            : 'admin.login';

        return \redirect()->route($loginRoute);
    }

    \App\Support\PortalAuth::syncDefaultGuard();

    // Regular authenticated dashboard access – data-driven operations command center
    return \app(\App\Http\Controllers\DashboardController::class)->index($request);
}

